import {
  isTimeInsideClip,
  clampValue,
  validateClip,
  computeTrim,
  applyTrim,
  splitClipAtTime,
  mergeClips,
  reorderClipIds,
  recalculateStartTimes,
  computeAudioSync,
  computeSplitAudioSync,
  findSnapPoint,
  buildSnapCandidates,
  timeToPx,
  pxToTime,
  clipToPixelRect,
  splitMarkerPosition,
  removeAndClose,
  insertAndRecalculate,
  totalDuration,
  MIN_CLIP_DURATION,
} from '@/lib/editor/trim-split-engine';
import type { ClipSegment, SnapCandidate } from '@/lib/editor/trim-split-engine';

function makeClip(overrides: Partial<ClipSegment> = {}): ClipSegment {
  return {
    id: 'clip-1',
    startTime: 1000,
    duration: 5000,
    inPoint: 0,
    outPoint: 5000,
    trackId: 'track-1',
    sourceDuration: 10000,
    name: 'Test Clip',
    ...overrides,
  };
}

// ─── isTimeInsideClip ──────────────────────────────────────────────

describe('isTimeInsideClip', () => {
  const clip = makeClip();

  it('returns true when time is inside clip', () => {
    expect(isTimeInsideClip(clip, 3000)).toBe(true);
  });

  it('returns false when time is before clip', () => {
    expect(isTimeInsideClip(clip, 500)).toBe(false);
  });

  it('returns false when time is after clip', () => {
    expect(isTimeInsideClip(clip, 7000)).toBe(false);
  });
});

// ─── clampValue ────────────────────────────────────────────────────

describe('clampValue', () => {
  it('clamps below minimum', () => {
    expect(clampValue(-10, 0, 100)).toBe(0);
  });

  it('returns value within range', () => {
    expect(clampValue(50, 0, 100)).toBe(50);
  });

  it('clamps above maximum', () => {
    expect(clampValue(200, 0, 100)).toBe(100);
  });
});

// ─── validateClip ──────────────────────────────────────────────────

describe('validateClip', () => {
  it('returns no errors for valid clip', () => {
    const clip = makeClip();
    expect(validateClip(clip)).toEqual([]);
  });

  it('reports short duration', () => {
    const clip = makeClip({ duration: 50 });
    const errors = validateClip(clip);
    expect(errors).toHaveLength(1);
    expect(errors[0]).toContain('below minimum');
  });

  it('reports negative inPoint', () => {
    const clip = makeClip({ inPoint: -100 });
    const errors = validateClip(clip);
    expect(errors.some((e) => e.includes('inPoint'))).toBe(true);
  });

  it('reports outPoint exceeding sourceDuration', () => {
    const clip = makeClip({ outPoint: 15000, sourceDuration: 10000 });
    const errors = validateClip(clip);
    expect(errors.some((e) => e.includes('exceeds sourceDuration'))).toBe(true);
  });
});

// ─── computeTrim edge='in' ─────────────────────────────────────────

describe('computeTrim edge=in', () => {
  it('trims in point normally', () => {
    const clip = makeClip();
    const result = computeTrim(clip, 'in', 1000);
    expect(result).not.toBeNull();
    expect(result!.inPoint).toBe(1000);
    expect(result!.startTime).toBe(2000);
    expect(result!.duration).toBe(4000);
  });

  it('clamps in point to 0 when delta is negative beyond origin', () => {
    const clip = makeClip({ inPoint: 500 });
    const result = computeTrim(clip, 'in', -1000);
    expect(result).not.toBeNull();
    expect(result!.inPoint).toBe(0);
  });

  it('returns null when resulting duration is below minimum', () => {
    const clip = makeClip({ duration: 200 });
    const result = computeTrim(clip, 'in', 150);
    expect(result).toBeNull();
  });
});

// ─── computeTrim edge='out' ────────────────────────────────────────

describe('computeTrim edge=out', () => {
  it('trims out point normally', () => {
    const clip = makeClip();
    const result = computeTrim(clip, 'out', -1000);
    expect(result).not.toBeNull();
    expect(result!.outPoint).toBe(4000);
    expect(result!.duration).toBe(4000);
  });

  it('clamps out point to sourceDuration', () => {
    const clip = makeClip({ outPoint: 9000, sourceDuration: 10000 });
    const result = computeTrim(clip, 'out', 5000);
    expect(result).not.toBeNull();
    expect(result!.outPoint).toBe(10000);
  });

  it('returns null when resulting duration is below minimum', () => {
    // inPoint=4960, outPoint=5000 → duration 40ms, trim out -100 clamps to 5060
    // But the clip duration itself (5000) is already below MIN. Use a clip where
    // we actively reduce outPoint enough that outPoint-inPoint < MIN
    const clip = makeClip({ inPoint: 0, outPoint: 150, duration: 150, sourceDuration: 200 });
    // Trimming out by -100 → newOutPoint = clamp(50, 100, 200) = 100, newDuration = 100
    // That equals MIN_CLIP_DURATION exactly, so it passes. Use -60 instead:
    // newOutPoint = clamp(90, 100, 200) = 100 → duration = 100 (still passes).
    // We need outPoint to go below inPoint+MIN. Use inPoint=50:
    const clip2 = makeClip({ inPoint: 50, outPoint: 200, duration: 150, sourceDuration: 300 });
    // Trim out by -200 → newOutPoint = clamp(0, 150, 300) = 150 → dur = 100 (passes).
    // The clamp prevents going below inPoint+MIN. So computeTrim out can never
    // return null — the clamp guarantees at least MIN_CLIP_DURATION. Test that
    // the result is clamped correctly instead:
    const result = computeTrim(clip, 'out', -100);
    expect(result).not.toBeNull();
    expect(result!.duration).toBe(MIN_CLIP_DURATION);
  });
});

// ─── applyTrim ─────────────────────────────────────────────────────

describe('applyTrim', () => {
  it('returns trimmed clip when valid', () => {
    const clip = makeClip();
    const result = applyTrim(clip, 'out', -1000);
    expect(result).not.toBeNull();
    expect(result!.outPoint).toBe(4000);
  });

  it('returns null when clip would be invalid', () => {
    const clip = makeClip({ duration: 50, outPoint: 50 });
    const result = applyTrim(clip, 'in', 10);
    expect(result).toBeNull();
  });
});

// ─── splitClipAtTime ───────────────────────────────────────────────

describe('splitClipAtTime', () => {
  it('splits clip into two valid segments', () => {
    const clip = makeClip();
    const result = splitClipAtTime(clip, 3000, 'a', 'b');
    expect(result).not.toBeNull();
    expect(result!.before.id).toBe('a');
    expect(result!.before.duration).toBe(2000);
    expect(result!.after.id).toBe('b');
    expect(result!.after.duration).toBe(3000);
    expect(result!.after.startTime).toBe(3000);
  });

  it('returns null when time is outside clip', () => {
    const clip = makeClip();
    expect(splitClipAtTime(clip, 500, 'a', 'b')).toBeNull();
  });

  it('returns null when split too close to start', () => {
    const clip = makeClip();
    expect(splitClipAtTime(clip, 1050, 'a', 'b')).toBeNull();
  });

  it('returns null when split too close to end', () => {
    const clip = makeClip();
    expect(splitClipAtTime(clip, 5950, 'a', 'b')).toBeNull();
  });
});

// ─── mergeClips ────────────────────────────────────────────────────

describe('mergeClips', () => {
  it('merges adjacent clips on same track', () => {
    const a = makeClip({ id: 'a', startTime: 0, duration: 2000, outPoint: 2000 });
    const b = makeClip({ id: 'b', startTime: 2000, duration: 3000, inPoint: 2000, outPoint: 5000 });
    const result = mergeClips(a, b);
    expect(result).not.toBeNull();
    expect(result!.duration).toBe(5000);
  });

  it('returns null for different tracks', () => {
    const a = makeClip({ id: 'a', trackId: 'track-1' });
    const b = makeClip({ id: 'b', trackId: 'track-2' });
    expect(mergeClips(a, b)).toBeNull();
  });

  it('returns null when gap is too large', () => {
    const a = makeClip({ id: 'a', startTime: 0, duration: 1000 });
    const b = makeClip({ id: 'b', startTime: 2000, duration: 1000 });
    expect(mergeClips(a, b)).toBeNull();
  });
});

// ─── reorderClipIds ────────────────────────────────────────────────

describe('reorderClipIds', () => {
  it('swaps items correctly', () => {
    const ids = ['a', 'b', 'c', 'd'];
    expect(reorderClipIds(ids, 0, 2)).toEqual(['b', 'c', 'a', 'd']);
  });

  it('returns copy when same index', () => {
    const ids = ['a', 'b', 'c'];
    const result = reorderClipIds(ids, 1, 1);
    expect(result).toEqual(['a', 'b', 'c']);
    expect(result).not.toBe(ids);
  });

  it('returns copy when index out of bounds', () => {
    const ids = ['a', 'b'];
    expect(reorderClipIds(ids, -1, 0)).toEqual(['a', 'b']);
    expect(reorderClipIds(ids, 0, 5)).toEqual(['a', 'b']);
  });
});

// ─── recalculateStartTimes ─────────────────────────────────────────

describe('recalculateStartTimes', () => {
  it('recalculates sequential start times', () => {
    const clips = [
      makeClip({ id: 'a', startTime: 100, duration: 1000 }),
      makeClip({ id: 'b', startTime: 200, duration: 2000 }),
    ];
    const result = recalculateStartTimes(clips);
    expect(result[0].startTime).toBe(0);
    expect(result[1].startTime).toBe(1000);
  });

  it('applies offset', () => {
    const clips = [
      makeClip({ id: 'a', duration: 1000 }),
      makeClip({ id: 'b', duration: 2000 }),
    ];
    const result = recalculateStartTimes(clips, 500);
    expect(result[0].startTime).toBe(500);
    expect(result[1].startTime).toBe(1500);
  });
});

// ─── computeAudioSync ──────────────────────────────────────────────

describe('computeAudioSync', () => {
  it('returns defaults when no audio', () => {
    const clip = makeClip({ audioUrl: undefined });
    const sync = computeAudioSync(clip);
    expect(sync.audioOffset).toBe(0);
    expect(sync.needsRegeneration).toBe(false);
  });

  it('returns offset when audio is trimmed', () => {
    const clip = makeClip({ audioUrl: 'audio.mp3', inPoint: 2000, outPoint: 5000 });
    const sync = computeAudioSync(clip);
    expect(sync.audioOffset).toBe(2000);
    expect(sync.audioDuration).toBe(3000);
    expect(sync.needsRegeneration).toBe(true);
  });

  it('returns no regeneration when inPoint is 0', () => {
    const clip = makeClip({ audioUrl: 'audio.mp3', inPoint: 0, outPoint: 5000 });
    const sync = computeAudioSync(clip);
    expect(sync.needsRegeneration).toBe(false);
  });
});

// ─── computeSplitAudioSync ─────────────────────────────────────────

describe('computeSplitAudioSync', () => {
  it('computes audio sync for both halves', () => {
    const clip = makeClip({ audioUrl: 'audio.mp3' });
    const split = splitClipAtTime(clip, 3000, 'a', 'b')!;
    const sync = computeSplitAudioSync(split);
    expect(sync.before.audioDuration).toBe(2000);
    expect(sync.after.audioDuration).toBe(3000);
  });
});

// ─── findSnapPoint ─────────────────────────────────────────────────

describe('findSnapPoint', () => {
  const candidates: SnapCandidate[] = [
    { time: 1000, label: 'start' },
    { time: 5000, label: 'end' },
  ];

  it('finds snap point within threshold', () => {
    // 100 px/s, 8px threshold = 80ms
    const result = findSnapPoint(1050, candidates, 100);
    expect(result).not.toBeNull();
    expect(result!.time).toBe(1000);
  });

  it('returns null when outside threshold', () => {
    const result = findSnapPoint(2000, candidates, 100);
    expect(result).toBeNull();
  });

  it('returns null for empty candidates', () => {
    const result = findSnapPoint(1000, [], 100);
    expect(result).toBeNull();
  });
});

// ─── buildSnapCandidates ───────────────────────────────────────────

describe('buildSnapCandidates', () => {
  it('builds candidates from clips', () => {
    const clips = [makeClip({ id: 'c1', startTime: 0, duration: 1000, name: 'Clip1' })];
    const result = buildSnapCandidates(clips);
    // start, end, origin = 3 candidates
    expect(result.length).toBe(3);
    expect(result.some((c) => c.label === 'Clip1 start')).toBe(true);
  });

  it('includes playhead when provided', () => {
    const result = buildSnapCandidates([], 5000);
    expect(result.some((c) => c.label === 'playhead')).toBe(true);
  });
});

// ─── timeToPx / pxToTime ───────────────────────────────────────────

describe('timeToPx', () => {
  it('converts time to pixels', () => {
    expect(timeToPx(1000, 100)).toBe(100);
  });

  it('handles fractional times', () => {
    expect(timeToPx(500, 200)).toBe(100);
  });
});

describe('pxToTime', () => {
  it('converts pixels to time', () => {
    expect(pxToTime(100, 100)).toBe(1000);
  });

  it('handles fractional pixels', () => {
    expect(pxToTime(50, 200)).toBe(250);
  });
});

// ─── clipToPixelRect ───────────────────────────────────────────────

describe('clipToPixelRect', () => {
  it('returns pixel rect for clip', () => {
    const clip = makeClip({ startTime: 2000, duration: 3000 });
    const rect = clipToPixelRect(clip, 100, 40);
    expect(rect.x).toBe(200);
    expect(rect.width).toBe(300);
    expect(rect.height).toBe(40);
  });
});

// ─── splitMarkerPosition ───────────────────────────────────────────

describe('splitMarkerPosition', () => {
  it('returns pixel position when inside clip', () => {
    const clip = makeClip({ startTime: 1000, duration: 5000 });
    const pos = splitMarkerPosition(clip, 3000, 100);
    expect(pos).toBe(200); // (3000-1000)/1000 * 100
  });

  it('returns null when outside clip', () => {
    const clip = makeClip({ startTime: 1000, duration: 5000 });
    expect(splitMarkerPosition(clip, 500, 100)).toBeNull();
  });
});

// ─── removeAndClose ────────────────────────────────────────────────

describe('removeAndClose', () => {
  it('removes clip and closes gap', () => {
    const clips = [
      makeClip({ id: 'a', startTime: 0, duration: 1000 }),
      makeClip({ id: 'b', startTime: 1000, duration: 2000 }),
      makeClip({ id: 'c', startTime: 3000, duration: 1000 }),
    ];
    const result = removeAndClose(clips, 'b');
    expect(result).toHaveLength(2);
    expect(result[0].startTime).toBe(0);
    expect(result[1].startTime).toBe(1000);
  });
});

// ─── insertAndRecalculate ──────────────────────────────────────────

describe('insertAndRecalculate', () => {
  it('inserts clip and recalculates', () => {
    const clips = [
      makeClip({ id: 'a', startTime: 0, duration: 1000 }),
      makeClip({ id: 'c', startTime: 1000, duration: 1000 }),
    ];
    const newClip = makeClip({ id: 'b', duration: 500 });
    const result = insertAndRecalculate(clips, newClip, 1);
    expect(result).toHaveLength(3);
    expect(result[0].id).toBe('a');
    expect(result[1].id).toBe('b');
    expect(result[2].id).toBe('c');
    expect(result[1].startTime).toBe(1000);
    expect(result[2].startTime).toBe(1500);
  });
});

// ─── totalDuration ─────────────────────────────────────────────────

describe('totalDuration', () => {
  it('returns 0 for empty array', () => {
    expect(totalDuration([])).toBe(0);
  });

  it('returns correct total for clips', () => {
    const clips = [
      makeClip({ startTime: 0, duration: 1000 }),
      makeClip({ startTime: 1000, duration: 2000 }),
    ];
    expect(totalDuration(clips)).toBe(3000);
  });
});
